import{_ as a,o as t,c as n,ae as o}from"./chunks/framework.D5VeguZw.js";const h=JSON.parse('{"title":"介绍","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md","lastUpdated":1783526795000}'),s={name:"guide/introduction.md"};function d(c,e,r,p,i,l){return t(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to &quot;介绍&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">Vue 3 Only</p><p>Uni Router 仅支持 uni-app 的 <strong>Vue 3</strong> 版本，不支持 Vue 2。核心功能依赖 Composition API（<code>inject</code> / <code>ref</code>）、<code>app.provide</code>、<code>&lt;script setup&gt;</code> 等特性。</p></div><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>Uni Router 是一个为 <a href="https://uniapp.dcloud.net.cn/" target="_blank" rel="noreferrer">uni-app</a> 设计的路由管理库，在 uni-app 原生导航 API 之上封装了一层，提供 <a href="https://router.vuejs.org/" target="_blank" rel="noreferrer">vue-router</a> 风格的 API 体验。</p><h2 id="为什么需要它" tabindex="-1">为什么需要它 <a class="header-anchor" href="#为什么需要它" aria-label="Permalink to &quot;为什么需要它&quot;">​</a></h2><p>uni-app 原生使用 <code>uni.navigateTo</code>、<code>uni.redirectTo</code>、<code>uni.switchTab</code> 等 API 进行页面跳转，存在以下痛点：</p><table tabindex="0"><thead><tr><th>痛点</th><th>原生方案</th><th>Uni Router 方案</th></tr></thead><tbody><tr><td>缺乏路由守卫</td><td>无法在导航前拦截</td><td><code>beforeEach</code> / <code>beforeResolve</code> / <code>afterEach</code></td></tr><tr><td>无路由元信息</td><td>无法为路由附加属性</td><td><code>meta</code> 字段，支持自定义扩展</td></tr><tr><td>API 碎片化</td><td>手动判断 navigateTo / switchTab</td><td>根据 <code>meta.isTab</code> 自动选择</td></tr><tr><td>缺少组合式 API</td><td>无法在 setup 中获取路由</td><td><code>useRouter()</code> / <code>useRoute()</code></td></tr><tr><td>错误处理不统一</td><td>回调式，无结构化错误码</td><td><code>NavigationFailure</code> + 错误码</td></tr><tr><td>参数传递受限</td><td>仅支持 URL query</td><td><code>params</code> 支持复杂数据 + 持久化</td></tr></tbody></table><h2 id="架构概览" tabindex="-1">架构概览 <a class="header-anchor" href="#架构概览" aria-label="Permalink to &quot;架构概览&quot;">​</a></h2><p>理解 Uni Router 的架构，有助于你后续掌握它的所有功能。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes one-dark-pro github-light vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                   你的应用代码                        │</span></span>
<span class="line"><span>│         router.push() / useRouter() / ...            │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                   Uni Router                         │</span></span>
<span class="line"><span>│  ┌──────────┐  ┌──────────┐  ┌───────────────────┐  │</span></span>
<span class="line"><span>│  │  导航方法  │  │  路由守卫  │  │  组合式 API / 插件 │  │</span></span>
<span class="line"><span>│  │ push 等   │→│ beforeEach│  │  useRouter 等     │  │</span></span>
<span class="line"><span>│  └────┬─────┘  └────┬─────┘  └───────────────────┘  │</span></span>
<span class="line"><span>│       │             │                                │</span></span>
<span class="line"><span>│  ┌────▼─────────────▼────┐  ┌───────────────────┐   │</span></span>
<span class="line"><span>│  │     导航执行引擎        │  │   路由匹配器       │   │</span></span>
<span class="line"><span>│  │ 守卫链 → API 调用 → 状态│  │  path / name 匹配 │   │</span></span>
<span class="line"><span>│  └────────┬──────────────┘  └───────────────────┘   │</span></span>
<span class="line"><span>│           │                                          │</span></span>
<span class="line"><span>│  ┌────────▼──────┐  ┌────────────┐  ┌────────────┐  │</span></span>
<span class="line"><span>│  │  拦截器(可选)   │  │  参数管理   │  │  状态同步   │  │</span></span>
<span class="line"><span>│  │ interceptUniApi│  │ params Map │  │ syncRoute  │  │</span></span>
<span class="line"><span>│  └───────────────┘  └────────────┘  └────────────┘  │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│              uni-app 原生导航 API                    │</span></span>
<span class="line"><span>│     uni.navigateTo / redirectTo / switchTab / ...    │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│              uni-app 页面栈（pages.json 声明）        │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="分层职责" tabindex="-1">分层职责 <a class="header-anchor" href="#分层职责" aria-label="Permalink to &quot;分层职责&quot;">​</a></h3><ol><li><strong>应用层</strong>：你的代码调用 <code>router.push()</code> 等 API</li><li><strong>Uni Router 层</strong>：守卫链调度、路由匹配、状态管理、参数传递</li><li><strong>uni-app 层</strong>：实际执行页面跳转的原生 API</li><li><strong>页面栈</strong>：uni-app 框架管理的页面栈，由 <code>pages.json</code> 静态声明</li></ol><div class="tip custom-block"><p class="custom-block-title">关键认知</p><p>Uni Router <strong>不替代</strong> uni-app 的导航机制，而是在其之上增加了一层&quot;调度层&quot;。所有导航最终仍通过 <code>uni.navigateTo</code> 等 API 执行，因此 uni-app 的所有限制（如 <code>switchTab</code> 不支持 query）依然存在，Uni Router 只是在这些限制之上做了优雅的封装和提示。</p></div><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h3 id="页面栈" tabindex="-1">页面栈 <a class="header-anchor" href="#页面栈" aria-label="Permalink to &quot;页面栈&quot;">​</a></h3><p>uni-app 维护一个页面栈，最大深度 10 层（小程序限制）。理解页面栈是掌握 Uni Router 的基础：</p><table tabindex="0"><thead><tr><th>操作</th><th>栈变化</th><th>对应 uni API</th></tr></thead><tbody><tr><td><code>push()</code></td><td>入栈（+1）</td><td><code>uni.navigateTo</code></td></tr><tr><td><code>replace()</code></td><td>替换栈顶</td><td><code>uni.redirectTo</code></td></tr><tr><td><code>relaunch()</code></td><td>清空栈后入栈</td><td><code>uni.reLaunch</code></td></tr><tr><td><code>back()</code></td><td>出栈（-n）</td><td><code>uni.navigateBack</code></td></tr><tr><td>TabBar 切换</td><td>关闭非 Tab 页</td><td><code>uni.switchTab</code></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">页面栈深度限制</p><p>小程序平台页面栈最大深度为 <strong>10 层</strong>。超过限制后 <code>navigateTo</code> 会失败。Uni Router 无法突破此限制，建议使用 <code>relaunch()</code> 重置栈，或用 <code>back()</code> 返回后再 <code>push()</code>。</p></div><h3 id="路由匹配" tabindex="-1">路由匹配 <a class="header-anchor" href="#路由匹配" aria-label="Permalink to &quot;路由匹配&quot;">​</a></h3><p>Uni Router 支持两种匹配方式：</p><ul><li><strong>路径匹配</strong>：<code>router.push({ path: &#39;pages/about/about&#39; })</code></li><li><strong>名称匹配</strong>：<code>router.push({ name: &#39;about&#39; })</code></li></ul><p>路径会自动规范化（补全前导 <code>/</code>）。名称匹配更安全，重构时只需修改路由配置。</p><div class="info custom-block"><p class="custom-block-title">与 vue-router 的区别</p><p>uni-app 的页面路径在编译时由 <code>pages.json</code> 确定，<strong>不支持动态路由</strong>（如 <code>/user/:id</code>）。如需传递参数，使用 <code>query</code> 或 <code>params</code>。</p></div><h3 id="路由守卫" tabindex="-1">路由守卫 <a class="header-anchor" href="#路由守卫" aria-label="Permalink to &quot;路由守卫&quot;">​</a></h3><p>守卫是 Uni Router 的核心能力，允许在导航前后插入逻辑：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes one-dark-pro github-light vp-code" tabindex="0"><code><span class="line"><span>导航触发</span></span>
<span class="line"><span>  → beforeEach（全局前置）</span></span>
<span class="line"><span>  → beforeEnter（路由独享）</span></span>
<span class="line"><span>  → beforeResolve（全局解析）</span></span>
<span class="line"><span>  → uni API 调用</span></span>
<span class="line"><span>  → afterEach（全局后置）</span></span></code></pre></div><p>守卫可通过 <code>next()</code> 放行、<code>next(false)</code> 中止、<code>next(location)</code> 重定向。详见<a href="./guards.html">路由守卫</a>。</p><h3 id="状态同步" tabindex="-1">状态同步 <a class="header-anchor" href="#状态同步" aria-label="Permalink to &quot;状态同步&quot;">​</a></h3><p>由于物理返回键和浏览器后退<strong>不经过路由器</strong>，路由器的 <code>currentRoute</code> 可能与实际页面不同步。Uni Router 提供 <code>syncRoute()</code> 方法从页面栈读取真实状态并更新。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes one-dark-pro github-light vp-code" tabindex="0"><code><span class="line"><span>用户按物理返回键</span></span>
<span class="line"><span>  → uni-app 原生 navigateBack（不经过路由器）</span></span>
<span class="line"><span>  → 路由器 currentRoute 仍是旧值</span></span>
<span class="line"><span>  → 页面 onShow 中调用 syncRoute()</span></span>
<span class="line"><span>  → currentRoute 更新为真实页面</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">这是 uni-app 的固有限制</p><p>路由器无法拦截物理返回键和浏览器后退。必须在页面的 <code>onShow</code> 生命周期中调用 <code>syncRoute()</code> 来保持状态一致。详见<a href="./compatibility.html">平台兼容性</a>。</p></div><h2 id="设计哲学" tabindex="-1">设计哲学 <a class="header-anchor" href="#设计哲学" aria-label="Permalink to &quot;设计哲学&quot;">​</a></h2><ol><li><p><strong>不替代，而是增强</strong>：Uni Router 不绕过 uni-app 的导航机制，所有导航最终走原生 API。这保证了跨平台兼容性，也意味着 uni-app 的限制依然生效。</p></li><li><p><strong>静态页面模型</strong>：uni-app 采用 <code>pages.json</code> 静态声明页面，Uni Router 尊重这一模型，不提供动态路由注册（<code>addRoute</code> / <code>removeRoute</code>）。</p></li><li><p><strong>渐进式采用</strong>：你可以只使用 <code>push</code> / <code>replace</code> 基础导航，也可以启用守卫、拦截器、参数传递等高级功能。<code>interceptUniApi</code> 默认关闭，不影响现有代码。</p></li><li><p><strong>类型安全</strong>：通过 <code>@meng-xi/vite-plugin</code> 的 <code>dts</code> 功能，路由名称和路径可获得自动补全和类型检查。</p></li></ol><h2 id="核心特性一览" tabindex="-1">核心特性一览 <a class="header-anchor" href="#核心特性一览" aria-label="Permalink to &quot;核心特性一览&quot;">​</a></h2><ul><li>🧭 <strong>四种导航</strong> — <code>push</code> / <code>replace</code> / <code>relaunch</code> / <code>back</code>，自动识别 TabBar 页面</li><li>🛡️ <strong>完整守卫链</strong> — <code>beforeEach</code> / <code>beforeResolve</code> / <code>afterEach</code> / <code>beforeEnter</code></li><li>🔄 <strong>可控重定向</strong> — 守卫中 <code>next(location, { mode })</code> 指定重定向方式</li><li>📦 <strong>页面参数</strong> — <code>params</code> 传递复杂数据，不暴露 URL，支持持久化</li><li>🔢 <strong>查询增强</strong> — <code>queryInt()</code> / <code>queryNumber()</code> / <code>queryBool()</code> 类型解析</li><li>📡 <strong>页面通信</strong> — <code>events</code> + <code>eventChannel</code> 双向通信，<code>useUniEventChannel</code> 支持所有导航方式</li><li>🎬 <strong>导航动画</strong> — App 端自定义动画，路由级默认值</li><li>🪝 <strong>组合式 API</strong> — <code>useRouter()</code> / <code>useRoute()</code> / <code>usePageChannel()</code> 响应式访问</li><li>⚡ <strong>API 拦截</strong> — 可选拦截原生导航 API，统一守卫流程</li><li>🛡️ <strong>超时保护</strong> — <code>guardTimeout</code> / <code>readyTimeout</code> 防止挂起</li><li>💪 <strong>TypeScript</strong> — 完整类型定义 + 智能提示</li></ul><h2 id="它不是什么" tabindex="-1">它不是什么 <a class="header-anchor" href="#它不是什么" aria-label="Permalink to &quot;它不是什么&quot;">​</a></h2><p>由于 uni-app 框架限制，以下 vue-router 特性<strong>不支持</strong>：</p><table tabindex="0"><thead><tr><th>特性</th><th>原因</th></tr></thead><tbody><tr><td>动态路由注册（<code>addRoute</code> / <code>removeRoute</code>）</td><td>uni-app 页面由 <code>pages.json</code> 静态声明</td></tr><tr><td>嵌套路由（<code>&lt;router-view&gt;</code>）</td><td>uni-app 无嵌套视图组件</td></tr><tr><td>动态路径匹配（<code>/user/:id</code>）</td><td>uni-app 页面路径固定</td></tr><tr><td><code>router.go(n)</code> / <code>router.forward()</code></td><td>小程序不支持前进导航</td></tr><tr><td>命名视图</td><td>uni-app 无多视图支持</td></tr><tr><td>路由懒加载</td><td>uni-app 有自己的代码分割机制</td></tr><tr><td>History 模式选择</td><td>uni-app 各端使用不同路由模式</td></tr></tbody></table><p>这些限制源于 uni-app 框架本身的设计，而非本库的不足。详见<a href="./differences.html">与 vue-router 的差异</a>。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./getting-started.html">快速开始</a> — 几分钟内集成到项目</li><li><a href="./navigation.html">路由导航</a> — 深入掌握四种导航方式</li><li><a href="./guards.html">路由守卫</a> — 理解守卫机制与实战</li><li><a href="./navigation-flow.html">导航流程原理</a> — 从源码角度理解导航全过程</li></ul>`,41)])])}const g=a(s,[["render",d]]);export{h as __pageData,g as default};
